import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

function p(t:string,s:string,d:'EASY'|'MEDIUM'|'HARD',o:number,story:string,pat:string,patEx:string,vs:any[],sols:any,cx:any,mem:string,quiz:any[],hints:string[],mistakes:string[]) {
  return {title:t,slug:s,difficulty:d,order:o,story,visualSteps:JSON.stringify(vs),pattern:pat,patternExplanation:patEx,solutions:JSON.stringify(sols),complexity:JSON.stringify(cx),memoryTrick:mem,quiz:JSON.stringify(quiz),hints:JSON.stringify(hints),commonMistakes:JSON.stringify(mistakes)};
}
function sol(py:string,java:string,cpp:string) {
  return {python:{code:py,lineExplanations:py.split('\n').map(()=>'')},java:{code:java,lineExplanations:java.split('\n').map(()=>'')},cpp:{code:cpp,lineExplanations:cpp.split('\n').map(()=>'')}};
}
function mcq(q:string,opts:string[],c:number,ex:string){return{type:'multiple_choice',question:q,options:opts,correct:c,explanation:ex};}

async function seedTopic(slug:string,problems:any[]) {
  const topic = await prisma.topic.findUnique({where:{slug}});
  if(!topic){console.log(`Topic ${slug} not found`);return;}
  for(const prob of problems) {
    const existing = await prisma.problem.findUnique({where:{slug:prob.slug}});
    if(existing){console.log(`  ⏭ ${prob.slug}`);continue;}
    await prisma.problem.create({data:{...prob,topicId:topic.id}});
    console.log(`  ✅ ${prob.slug}`);
  }
}

